#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int ti, xi, yi, Xi, Yi;
        int prev_ti = -1, prev_xi = -1, prev_yi = -1, prev_Xi = -1, prev_Yi = -1;
        int valid = 1;
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d %d %d", &ti, &xi, &yi, &Xi, &Yi);
            if (ti != prev_ti + 1) {
                valid = 0;
                break;
            }
            if (xi != prev_xi && yi != prev_yi && Xi != prev_Xi && Yi != prev_Yi) {
                valid = 0;
                break;
            }
            if (xi == Xi && yi == Yi) {
                valid = 0;
                break;
            }
            prev_ti = ti;
            prev_xi = xi;
            prev_yi = yi;
            prev_Xi = Xi;
            prev_Yi = Yi;
        }
        if (valid) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

